@charset "UTF-8";
#map-container {
  width: 100%;
  height: 100%;
  position: relative;
}

#map {
  width: 100%;
  height: 400px; /* Ajusta según el tamaño de tu widget */
  background: #f8f9fa;
  border-radius: 8px;
}

.info {
  padding: 10px;
  font-family: Arial, sans-serif;
  background: white;
  background: rgba(255, 255, 255, 0.9);
  box-shadow: 0 0 15px rgba(0, 0, 0, 0.2);
  border-radius: 5px;
  position: absolute;
  top: 10px;
  right: 10px;
  z-index: 1000;
  min-width: 150px;
}

.info h4 {
  margin: 0 0 5px;
  color: #777;
}

#map {
  width: 100%;
  height: 100%;
  min-height: 500px;
  border-radius: 8px;
}

/* Tooltip flotante grande */
.large-floating-tooltip {
  background: rgba(0, 0, 0, 0.85);
  color: white;
  padding: 15px 20px;
  border-radius: 12px;
  box-shadow: 0 8px 25px rgba(0, 0, 0, 0.3);
  border: 3px solid #3388ff;
  min-width: 300px;
  backdrop-filter: blur(5px);
}

.floating-title {
  font-size: 20px !important;
  font-weight: bold;
  color: #3388ff;
  margin-bottom: 15px;
  text-align: center;
  letter-spacing: 1px;
  text-transform: uppercase;
  border-bottom: 2px solid #3388ff;
  padding-bottom: 8px;
}

.data-row {
  margin: 12px 0;
  display: flex;
  flex-direction: column;
}

.data-label {
  font-size: 20px !important;
  color: #ffcc00;
  font-weight: bold;
  margin-bottom: 5px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.data-value {
  font-size: 26px !important;
  font-weight: bold;
  color: white;
  background: rgba(51, 136, 255, 0.2);
  padding: 8px 12px;
  border-radius: 6px;
  border-left: 4px solid #ffcc00;
}

/* Tooltip estándar de Leaflet (mejorado) */
.custom-tooltip {
  font-size: 16px !important;
  font-weight: bold;
  background: rgba(0, 0, 0, 0.9) !important;
  border: 2px solid #3388ff !important;
  border-radius: 8px !important;
  color: white !important;
  padding: 12px 15px !important;
}

.custom-tooltip::before {
  border-top-color: #3388ff !important;
}

/* Popup mejorado */
.popup-content {
  font-size: 14px;
  max-width: 300px;
}

.popup-content h3 {
  color: #3388ff;
  margin-top: 0;
  border-bottom: 2px solid #f0f0f0;
  padding-bottom: 5px;
}

/* Asegurar que los textos sean legibles */
.leaflet-tooltip,
.leaflet-popup-content {
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif !important;
}

