appsmith.onReady(() => {
  // Función principal
  (() => {
    // Inicializar mapa
    const map = L.map('map').setView([10.180, -68.004], 10);

    // Capa base
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '© OpenStreetMap',
      maxZoom: 19
    }).addTo(map);

    // Limpiar capa anterior si existe
    if (window.parroquiasLayer) {
      map.removeLayer(window.parroquiasLayer);
    }

    // Obtener datos GeoJSON
    let geoJSONData = null;

    // IMPORTANTE: Cambia 'Query1' por el nombre de TU query
    try {
      if (appsmith.model && appsmith.model.data && appsmith.model.data[0]) {
        geoJSONData = appsmith.model.data[0].geojson_collection;
      }
    } catch (e) {
      console.error("Error:", e);
    }

    // Si no hay datos, retornar
    if (!geoJSONData || !geoJSONData.features) {
      console.warn("No hay datos GeoJSON válidos");
      return {
        status: "waiting",
        message: "Esperando datos..."
      };
    }

    // Crear tooltip flotante con estilo grande
    const floatingTooltip = L.control({
      position: 'topright'
    });
    floatingTooltip.onAdd = function () {
      this._div = L.DomUtil.create('div', 'floating-tooltip');
      this._div.style.display = 'none';
      return this._div;
    };
    floatingTooltip.addTo(map);

    // Crear capa GeoJSON con tooltips mejorados
    window.parroquiasLayer = L.geoJSON(geoJSONData, {
      style: {
        fillColor: '#3388ff',
        weight: 1.5,
        opacity: 0.8,
        color: '#ffffff',
        fillOpacity: 0.2
      },
      onEachFeature: function (feature, layer) {
        // Extraer nombres de municipio y parroquia
        // Ajusta estos nombres según cómo vengan en tus datos
        const props = feature.properties || {};

        // Intentar encontrar municipio (probando diferentes nombres comunes)
        const municipio = props.municipio || props.municipio_nombre || props.municipio_name || props.municipality || props.nombre_municipio || 'Municipio no definido';

        // Intentar encontrar parroquia
        const parroquia = props.parroquia || props.parroquia_nombre || props.parroquia_name || props.parish || props.nombre_parroquia || props.nombre || 'Parroquia no definida';

        // Crear tooltip con letras grandes
        const tooltipContent = `
        <div class="large-tooltip">
          <div class="tooltip-header">INFORMACIÓN</div>
          <div class="tooltip-item">
            <span class="tooltip-label">MUNICIPIO:</span>
            <span class="tooltip-value">${municipio}</span>
          </div>
          <div class="tooltip-item">
            <span class="tooltip-label">PARROQUIA:</span>
            <span class="tooltip-value">${parroquia}</span>
          </div>
        </div>
      `;

        // Bind tooltip que se muestra al pasar el cursor
        layer.bindTooltip(tooltipContent, {
          sticky: true,
          // Se mueve con el cursor
          direction: 'top',
          // Aparece arriba del cursor
          offset: [0, -10],
          // Ajuste de posición
          className: 'custom-tooltip',
          // Clase CSS personalizada
          opacity: 1 // Totalmente visible
        });

        // Mostrar tooltip flotante grande cuando el mouse entra
        layer.on('mouseover', function (e) {
          // Cambiar estilo del polígono
          layer.setStyle({
            fillOpacity: 0.5,
            weight: 3,
            color: '#ff7800'
          });

          // Mostrar tooltip flotante grande
          const floatingDiv = floatingTooltip._div;
          floatingDiv.innerHTML = `
          <div class="large-floating-tooltip">
            <div class="floating-title">UBICACIÓN ACTUAL</div>
            <div class="floating-data">
              <div class="data-row">
                <span class="data-label">MUNICIPIO:</span>
                <span class="data-value">${municipio}</span>
              </div>
              <div class="data-row">
                <span class="data-label">PARROQUIA:</span>
                <span class="data-value">${parroquia}</span>
              </div>
            </div>
          </div>
        `;
          floatingDiv.style.display = 'block';

          // También abrir tooltip estándar de Leaflet
          layer.openTooltip(e.latlng);
        });

        // Ocultar tooltip flotante cuando el mouse sale
        layer.on('mouseout', function () {
          // Restaurar estilo original
          layer.setStyle({
            fillOpacity: 0.2,
            weight: 1.5,
            color: '#ffffff'
          });

          // Ocultar tooltip flotante
          floatingTooltip._div.style.display = 'none';
          layer.closeTooltip();
        });

        // Popup al hacer click (opcional)
        const popupContent = `
        <div class="popup-content">
          <h3>${parroquia}</h3>
          <p><strong>Municipio:</strong> ${municipio}</p>
          ${Object.keys(props).map(key => key !== 'municipio' && key !== 'parroquia' ? `<p><strong>${key}:</strong> ${props[key]}</p>` : '').join('')}
        </div>
      `;
        layer.bindPopup(popupContent);
      }
    }).addTo(map);

    // Ajustar vista
    if (geoJSONData.features.length > 0) {
      map.fitBounds(window.parroquiasLayer.getBounds());
    }
    return {
      status: "success",
      features: geoJSONData.features.length,
      map: "loaded"
    };
  })();
});
function renderGeoJSON() {
  const stats = appsmith.model.stats || [];
  const rawGeoms = appsmith.model.geometrias || [];
  if (!rawGeoms.length) return;

  // 1. Convertimos los datos de Postgres en un objeto GeoJSON real
  const geoJSONCompleto = {
    type: "FeatureCollection",
    features: rawGeoms.map(g => {
      // Buscamos si este municipio tiene estadísticas en la otra BD
      const statMatch = stats.find(s => s.alcaldia === g.municipio);
      return {
        type: "Feature",
        geometry: g.geometry,
        properties: {
          NOMBRE: g.municipio,
          CODIGO: g.municipio,
          total: statMatch ? statMatch.total : 0,
          info: statMatch ? statMatch.detalles : 'Sin registros'
        }
      };
    })
  };

  // 2. Dibujamos el mapa (Leaflet)
  if (geojsonLayer) map.removeLayer(geojsonLayer);
  geojsonLayer = L.geoJson(geoJSONCompleto, {
    style: feature => ({
      fillColor: feature.properties.total > 0 ? '#27ae60' : '#ecf0f1',
      weight: 2,
      opacity: 1,
      color: 'white',
      fillOpacity: 0.7
    }),
    onEachFeature: (feature, layer) => {
      layer.on({
        mouseover: e => {
          const p = feature.properties;
          document.getElementById('info-content').innerHTML = `
                        <b>${p.NOMBRE}</b><br>
                        Registros: ${p.total}<br>
                        <small>${p.info}</small>
                    `;
          e.target.setStyle({
            weight: 4,
            color: '#333'
          });
        },
        mouseout: e => {
          geojsonLayer.resetStyle(e.target);
          document.getElementById('info-content').innerHTML = 'Pasa el ratón sobre un municipio';
        }
      });
    }
  }).addTo(map);
}

